        <div className="form-group">
          <label htmlFor="landWidth">Land Width (ft)</label>
          <input
            type="number"
            id="landWidth"
            name="landWidth"
            value={formData.landWidth}
            onChange={handleChange}
            placeholder="Enter land width"
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="numberOfPlots">Number of Plots</label>
          <input
            type="number"
            id="numberOfPlots"
            name="numberOfPlots"
            value={formData.numberOfPlots}
            onChange={handleChange}
            placeholder="Enter number of plots"
            required
          />
        </div>

        {numPlots > 0 && (
          <div className="grid-info">
            <p>Grid Size: {rows} rows × {cols} cols</p>
            <p>Individual Plot: {plotLength.toFixed(2)} ft × {plotWidth.toFixed(2)} ft</p>
          </div>
        )}

        {numPlots > 0 && (
          <div 
            className="plot-preview"
            style={{
              display: 'grid',
              gridTemplateColumns: `repeat(${cols}, 40px)`,
              gridTemplateRows: `repeat(${rows}, 40px)`,
              gap: '4px',
              marginTop: '16px'
            }}
          >
            {Array.from({ length: numPlots }, (_, index) => (
              <div
                key={index}
                style={{
                  border: '1px solid #333',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '10px',
                  backgroundColor: '#fff'
                }}
              >
                {index + 1}
              </div>
            ))}
          </div>
        )}

        <button type="submit" className="submit-btn">Create Project</button>
      </form>
    </div>
  );
};

export default CreateProject;

